struct UserAccount: Codable, Equatable {
    let userId: String
    var appliedPromoCode: String?
    var appliedDiscountPercent: Int?
    var appliedAt: Date?
}

final class PromoManager: ObservableObject {
    static let shared = PromoManager()

    @Published private(set) var currentUser: UserAccount
    @Published private(set) var lastHandledLink: URL?
    @Published private(set) var lastError: String?

    private let storage = UserAccountStore()
    private let promoHost = "myapp.com"
    private let promoPath = "/promo"

    private init() {
        self.currentUser = storage.load() ?? UserAccount(userId: "user_001", appliedPromoCode: nil, appliedDiscountPercent: nil, appliedAt: nil)
    }

    func handleUniversalLink(_ url: URL) -> Bool {
        lastHandledLink = url
        lastError = nil

        guard isExpectedPromoURL(url) else {
            lastError = "Unrecognized link."
            return false
        }

        guard let promo = PromoLinkParser.parse(url: url) else {
            lastError = "Invalid promo parameters."
            return false
        }

        applyPromo(promo.code, discountPercent: promo.discountPercent)
        return true
    }

    func applyPromo(_ code: String, discountPercent: Int) {
        currentUser.appliedPromoCode = code
        currentUser.appliedDiscountPercent = discountPercent
        currentUser.appliedAt = Date()
        storage.save(currentUser)
    }

    func clearPromo() {
        currentUser.appliedPromoCode = nil
        currentUser.appliedDiscountPercent = nil
        currentUser.appliedAt = nil
        storage.save(currentUser)
        lastError = nil
    }

    private func isExpectedPromoURL(_ url: URL) -> Bool {
        guard let host = url.host?.lowercased(), host == promoHost else { return false }
        return url.path == promoPath
    }
}

struct PromoLinkParser {
    static func parse(url: URL) -> (code: String, discountPercent: Int)? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }
        let items = components.queryItems ?? []

        let code = items.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)
        let discountString = items.first(where: { $0.name.lowercased() == "discount" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)

        guard let codeUnwrapped = code, !codeUnwrapped.isEmpty else { return nil }
        guard let ds = discountString, let discount = Int(ds), (0...100).contains(discount) else { return nil }

        return (codeUnwrapped, discount)
    }
}

final class UserAccountStore {
    private let key = "UserAccountStore.currentUser"

    func save(_ account: UserAccount) {
        do {
            let data = try JSONEncoder().encode(account)
            UserDefaults.standard.set(data, forKey: key)
        } catch {
            // ignore
        }
    }

    func load() -> UserAccount? {
        guard let data = UserDefaults.standard.data(forKey: key) else { return nil }
        do {
            return try JSONDecoder().decode(UserAccount.self, from: data)
        } catch {
            return nil
        }
    }
}